import{_ as e,c as t,o as a,f as o}from"./chunks/framework.BOAZPCR7.js";const _=JSON.parse('{"title":"Pleiotropic mutational effects on function and stability constrain the antigenic evolution of influenza hemagglutinin","description":"","frontmatter":{"layout":"post","title":"Pleiotropic mutational effects on function and stability constrain the antigenic evolution of influenza hemagglutinin","date":"2025-05-27T00:00:00.000Z","author":"Jesse Bloom","head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/posts/2025-05-27_yu-h3.html"}]]},"headers":[],"relativePath":"posts/2025-05-27_yu-h3.md","filePath":"posts/2025-05-27_yu-h3.md"}'),r={name:"posts/2025-05-27_yu-h3.md"},s=o('<p>In a new study led by grad student Tim Yu and <a href="https://www.biorxiv.org/content/10.1101/2025.05.24.655919v1" target="_blank" rel="noreferrer">posted on bioRxiv today</a>, we used pseudovirus deep mutational scanning to measure how all mutations to a recent H3N2 HA affect cell entry, stability, and antibody escape. The results help shed light on how the pleiotropic effects of mutations shape influenza evolution.</p><hr><p>For accessible summaries of the study, see:</p><ul><li><a href="https://bsky.app/profile/jbloomlab.bsky.social/post/3lq63xmb5kc2r" target="_blank" rel="noreferrer">This Bluesky thread</a>, which can be read more easily in <a href="https://skywriter.blue/pages/jbloomlab.bsky.social/post/3lq63xmb5kc2r" target="_blank" rel="noreferrer">threaded form here</a>.</li><li><a href="https://x.com/jbloom_lab/status/1927399924519367090" target="_blank" rel="noreferrer">This X thread</a></li></ul><p>All the data are available for interactive visualization and download at <a href="https://dms-vep.org/Flu_H3_Massachusetts2022_DMS/" target="_blank" rel="noreferrer">https://dms-vep.org/Flu_H3_Massachusetts2022_DMS/</a></p><h2 id="update" tabindex="-1">Update <a class="header-anchor" href="#update" aria-label="Permalink to &quot;Update&quot;">​</a></h2><p>The final version of this article has been <a href="https://www.nature.com/articles/s41559-025-02895-1" target="_blank" rel="noreferrer">published in <em>Nature Ecology and Evolution</em></a> alongside a <a href="https://www.nature.com/articles/s41559-025-02928-9" target="_blank" rel="noreferrer">nice News and Views</a>.</p>',7),n=[s];function l(i,h,c,p,u,d){return a(),t("div",null,n)}const m=e(r,[["render",l]]);export{_ as __pageData,m as default};
